module top_module(
    input clk,
    input in,
    input reset,
    output reg out
);     // State Encoding
    parameter A = 0, B = 1;
    reg [1:0] unused_state, next;

    // State Transition Logic
    always @(*) begin
        case (unused_state)
            A: next = in ? A : A;
            B: next = in ? B : B;
        endcase
    end

    // State Register with synchronous Reset
    always @(posedge clk) begin
        if (reset) unused_state <= B;
        else unused_state <= next;
    end

    // Output Logic
    always @(*) begin
        case (unused_state)
            A: out = 0;
            B: out = 1;
        endcase
    end
endmodule
